var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"WAMAN_LEGACY_NULL_EXTRA","text":{"KOREA":"가람 씨! 큰일이에요! 아티팩트의 과부하가 심해지고 있습니다!","JPN":"ヒカリさん！　大変です！　アーティファクトの過負荷が深刻になっています！","ENG":"Garam! This is bad! The Artifact's overload is getting worse!","TWN":"嘉蘭！出大事了！人造神器的超載越來越嚴重！"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WAMAN_LEGACY_NULL_EXTRA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAN_LEGACY_NULL_EXTRA","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"WAMAN_LEGACY_NULL_EXTRA","text":{"KOREA":"노멀 플레이어들의 상황도 심각해요. 마치 단체로 폭주한 것만 같아요!","JPN":"ノーマルプレイヤーたちの様子も危険です。まるで暴走しているような感じです！","ENG":"The situation for normal players is not good either. It's as if they've all gone mad!","TWN":"普通玩家的情況也很嚴重，就像集體暴走一樣！"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WAMAN_LEGACY_NULL_EXTRA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAN_LEGACY_NULL_EXTRA","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"MAN_LEGACY_NULL_EXTRA","text":{"KOREA":"필드, 몬스터, 전부 통제를 벗어나고 있습니다!","JPN":"フィールド、モンスター、すべてコントロールできなくなっています！","ENG":"The field, the monsters–everything is getting out of control!","TWN":"地圖、怪物，全都失控了！"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WAMAN_LEGACY_NULL_EXTRA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAN_LEGACY_NULL_EXTRA","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"……서버를 차단하는 방법밖에 없겠군요.","JPN":"……サーバーをシャットダウンするしかありませんね。","ENG":"...We have no choice but to shut down the server.","TWN":"……看來只能關閉伺服器了。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"유저들을 모두 내보내면 과부하가 줄어들 테니, 그동안 점검을 진행하겠어요.","JPN":"ユーザーをすべて追い出したら過負荷も収まるから、その間にメンテナンスを行います。","ENG":"The overload will lessen once all the players are logged out. I'll do a maintenance in the meantime.","TWN":"把所有玩家都送出去的話，壓力就會減輕，這段時間我會進行檢查。"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MAN_LEGACY_NULL_EXTRA","text":{"KOREA":"그, 그게…….","JPN":"そ、その……","ENG":"Th-the thing is...","TWN":"那，那個……"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_LEGACY_NULL_EXTRA","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MAN_LEGACY_NULL_EXTRA","text":{"KOREA":"오버로드에서 침식파와 비슷한 파장이…….","JPN":"オーバーロードから侵食波に似た波長が……","ENG":"We're detecting something similar to a Corruption ray from Overlord...","TWN":"在超載中發現到與侵蝕波相似的波長……"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_LEGACY_NULL_EXTRA","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"뭐, 뭐라고요?!","JPN":"な、何ですって！？","ENG":"W-what did you just say?!","TWN":"什，什麼？！"},"stage":{"bg":"DATABASE_02","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"여기까지…… 오늘 수업.","JPN":"ここまで……今日の授業。","ENG":"Class... dismissed.","TWN":"今天的課……就到這裡。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"질문 있니……? 뭐든 좋아.","JPN":"質問ある……？　なんでもいい。","ENG":"Do you have any questions...? Any question is fine.","TWN":"有問題嗎……？什麼問題都可以。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그 땅꼬마 선생은 어디 갔어? 설마 그만둔 거야?","JPN":"あのチビ先生はどこ行ったの？　まさかやめたの？","ENG":"Where did the pipsqueak teacher go? Did she quit?","TWN":"那個矮冬瓜老師去哪了？難道辭職了嗎？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"내가 담당할 거야…… 당분간.","JPN":"私が担当する……しばらく。","ENG":"I'll be teaching the class... for the time being.","TWN":"暫時我會負責……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"많이…… 바쁠 테니까.","JPN":"かなり……忙しいから。","ENG":"She's... extremely busy.","TWN":"她……會很忙。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"……그 땅꼬마가 일반인들을 유입시킨 뒤로 뭔가 이상해지고 있잖아.","JPN":"……あのチビが一般人を受け入れてから何かおかしくなってる。","ENG":"...Things have been getting weird ever since she allowed normal players to join.","TWN":"……自從那個矮冬瓜把普通人引進來之後，一切都變得奇怪了。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"당신은 뭔가 느끼는 거 없어?","JPN":"あんたもわかるでしょ？","ENG":"Haven't you felt anything off?","TWN":"你沒感覺到什麼嗎？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"뭐, 뭐라고 말 좀 해보라고!","JPN":"何黙ってるの？　何か言ってよ！","ENG":"A-at least say something!","TWN":"你，你說話啊！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"나이엘 진정해! 선생님이 그걸 모르시겠어?","JPN":"ナイエル、落ち着いて！　先生だってわかってるよきっと。","ENG":"Naielle, calm down! I'm sure she knows.","TWN":"奈爾，冷靜點！老師怎麼會不知道呢？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L35_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"일반인들도 유입될 거라는 건 오리엔테이션 때부터 말씀하셨잖아.","JPN":"一般人も入るようになるって話は、オリエンテーションでもしたじゃない。","ENG":"She told us that normal players would be joining during the orientation class, remember?","TWN":"從新學期說明會時起就說過普通人也會加入的吧。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"못 하겠네…… 부정.","JPN":"できないね……否定。","ENG":"I can't... deny it.","TWN":"……我無法否認。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"시기상조가 맞아…… 일반인 유입.","JPN":"まだ早い……一般人を受け入れるのは。","ENG":"It was too early... letting non-Counters join.","TWN":"普通人加入……時機尚早。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"……당신 분명 미리네라는 사람이랑 잘 아는 사이였지?","JPN":"……あんた、確かマリって人と知り合いなんでしょ？","ENG":"...You're friends with this Mi Rinae person, right?","TWN":"……你和宓璃奈那個人關係很好吧？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"역시 난 그 사람을 만나야겠어. 연락이든 뭐든 좋으니까……!","JPN":"やっぱりあの人に会わないと。連絡とかなにか……！","ENG":"I need to see her. Give me something! Her phone number or anything–!","TWN":"果然我還是要去見那個人，給我她的聯絡方式……！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"실례할게…… 나머진 내일 수업 때 말하자.","JPN":"失礼するね……続きは明日の授業で話そう。","ENG":"Excuse me... Let's talk more during the next class.","TWN":"抱歉……剩下的明天上課時再說吧。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L45_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"자, 잠깐!!","JPN":"ま、待って！！","ENG":"W-wait!","TWN":"等，等等！！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SUBMACHINEGUN_TIDE_NULL_NULL","text":{"KOREA":"이쪽입니다! 모두 신속히 대피해 주십쇼!","JPN":"こっちです！　皆さん、迅速に避難してください！","ENG":"This way! Everyone, please evacuate quickly!","TWN":"這邊！請大家迅速撤離！"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SUBMACHINEGUN_TIDE_NULL_NULL","text":{"KOREA":"침식현상은 종종 있는 일이긴 하지만 최근 들어 그 빈도가 심하네요.","JPN":"侵食現象はよくあることですが、最近は頻度がより高くなってますね。","ENG":"The frequency of the Counterside Effect has increased these past few days.","TWN":"侵蝕現象雖然有時會發生，但最近頻率太高了。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SUBMACHINEGUN_TIDE_NULL_NULL","text":{"KOREA":"대체 원인이 뭘까요? 설마 또 거대한 사건의 전조가 되는 건 아닐지…….","JPN":"いったい何が原因でしょうか？　まさか、これもまた大きな事件の前兆では……","ENG":"What's the cause of it? Is it another omen of a massive incident...?","TWN":"究竟是什麼原因呢？難道又是巨大事件的前兆……"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"지금 상황에서 원인을 추론하는 건 의미가 없어.","JPN":"今の状況で原因を推測するのは無意味だ。","ENG":"It's meaningless to infer the cause of it right now.","TWN":"在現在的情況下推測原因是沒有意義的。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"GUNSHIELD_TIDE_NULL_NULL","text":{"KOREA":"최대한 많은 사람을 구한다. 우리들은 오직 그것만 생각하면 돼.","JPN":"なるべく多くの人を助ける。私たちはそれだけ考えればいい。","ENG":"We must save as many people as we can. That's all we should focus on.","TWN":"盡可能救更多的人，我們只需要想著這一點就行了。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SUBMACHINEGUN_TIDE_NULL_NULL","text":{"KOREA":"그건 물론 알고 있습니다.","JPN":"それはもちろん承知しています。","ENG":"Yes, of course.","TWN":"那是當然的。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SUBMACHINEGUN_TIDE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUNSHIELD_TIDE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"총괄님. 아티팩트 오버로드를 도입한 이후부터 침식현상이 급증하고 있습니다.","JPN":"総括ディレクター、アーティファクトのオーバーロードを導入してから、侵食現象が急増しています。","ENG":"Chief. The Counterside Effect has been rapidly increasing ever since the implementation of the Artifact, Overlord.","TWN":"總監，自從引入神器超載後，侵蝕現象急劇增加。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"일견에서는 카운터즈 레거시가 원인임을 주장하고 있는데, 현재 어떤 조치를 하고 계신가요?","JPN":"一角ではカウンターズ・レガシーが原因だと主張する声が上がっていますが、何か措置を行っているのでしょうか？","ENG":"Some are claiming that Counters Legacy might be the cause. What shall we do about this?","TWN":"有觀點認為是制裁者的遺產引起的，目前你們正在採取什麼措施？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"그, 그러니까…… 혀, 현재로선…… 저희도 조, 조사중입니다.","JPN":"そ、その……げ、現在……私たちもちょ、調査を行っています。","ENG":"U-um... w-we... are currently i-investigating the issue.","TWN":"那，那個……現……目前……我們也在，在調查中。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"오버로드의 안정성 수치는…… 야, 양호해요.","JPN":"オーバーロードの安定性数値は……りょ、良好です。","ENG":"Overlord's stability figures are... g-good.","TWN":"超載的穩定性數值……嗯，良好。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"침식현상뿐만 아니라, 카운터를 모방한 각종 범죄율도 치솟고 있어요.","JPN":"侵食現象だけでなく、カウンターを模倣した各種犯罪率も上がっています。","ENG":"It's not just the Counterside Effect, but various crimes of Counter-imitation are also soaring.","TWN":"不僅是侵蝕現象，模仿制裁者的各種犯罪率也在飆升。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"전문가들은 동경심을 비춰준다는 오버로드 때문이라고 주장하고 있습니다만…….","JPN":"専門家たちは、憧れを反映するというオーバーロードが原因だと主張していますが……","ENG":"Experts claim that it's due to the effect of Overlord, as it mirrors admiration...","TWN":"專家們聲稱這是因為超載反映了他們對於制裁者的憧憬……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHAIRMAN_LEGACY_NULL_EXTRA","text":{"KOREA":"가람! 이게 어떻게 된 건가!","JPN":"カワセ！　いったいどうなってるんだ！","ENG":"Garam! What's going on?!","TWN":"嘉蘭！這到底是怎麼回事！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHAIRMAN_LEGACY_NULL_EXTRA","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L29_1","type":"dialog","speaker":"CHAIRMAN_LEGACY_NULL_EXTRA","text":{"KOREA":"분명 오버로드는 안정성이 확증됐다고 호언장담하지 않았나?","JPN":"確かオーバーロードの安定性は検証済みだと言っていなかったか？","ENG":"Didn't you assure me that Overlord's stability was confirmed?","TWN":"不是說超載已經確認穩定了嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHAIRMAN_LEGACY_NULL_EXTRA","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"그, 그게…….","JPN":"そ、その……","ENG":"Th-the thing is...","TWN":"那，那個……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CHAIRMAN_LEGACY_NULL_EXTRA","text":{"KOREA":"이대로 서버를 내렸다간, 오버로드의 폭주를 인정하는 것이 돼.","JPN":"このままサーバーをシャットダウンするのは、オーバーロードの暴走を認めることになる。","ENG":"If we shut down the server now, we're just admitting that Overlord went out of control.","TWN":"就這樣關閉伺服器的話，就等於承認超載暴走了。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHAIRMAN_LEGACY_NULL_EXTRA","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHAIRMAN_LEGACY_NULL_EXTRA","text":{"KOREA":"그렇게 되면 회사는 물론, 우리 모두 끝장이야!","JPN":"そうなったらこの会社はもちろん、我々まで終わってしまう！","ENG":"And if that happens, we'll all go down along with the company!","TWN":"那樣的話，不僅公司，我們所有人都完蛋了！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHAIRMAN_LEGACY_NULL_EXTRA","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CHAIRMAN_LEGACY_NULL_EXTRA","text":{"KOREA":"어떻게든 해결해. 그렇지 않으면 모든 책임은 당신이 지게 될 테니까!","JPN":"どうにか解決するんだ。でないとすべての責任は君が背負うことになるからな！","ENG":"Fix it! Otherwise, you'll be taking full responsibility for this!","TWN":"無論如何都要解決，否則所有責任都將由你承擔！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CHAIRMAN_LEGACY_NULL_EXTRA","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CHAIRMAN_LEGACY_NULL_EXTRA","text":{"KOREA":"젠장! 그냥 처음부터 진보라 씨에게 맡겨야 했어!","JPN":"くそ！　最初からタカダに任せるべきだった！","ENG":"Dammit! I should have just let Jin Bora take on the project!","TWN":"可惡！一開始就應該交給陳寶拉的！"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L38_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L39_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"유, 유저들의 문제는…… 오, 오버로드와는 무, 무관한…….","JPN":"ゆ、ユーザーの問題は……お、オーバーロードとは無関係の……","ENG":"Th-the players' issue has... n-nothing to do with O-Overlord...","TWN":"用、玩家們的問題……和、和超載無、無關……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"네? 다시 한번 말씀해 주실 수 있을까요?","JPN":"はい？　すみません、もう一度お願いします。","ENG":"What? Could you say that again?","TWN":"什麼？可以再說一遍嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GARAM_LEGACY_NULL_NULL","text":{"KOREA":"그, 그, 그러니까…….","JPN":"だ、だ、だから……","ENG":"S-so...","TWN":"我，我，我說……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GARAM_LEGACY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"VIOLET_LEGACY_NULL_NPC","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"VIOLET_LEGACY_NULL_NPC","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CHEOLSU_LEGACY_NULL_NPC","text":{"KOREA":"하하, 드디어 접속하게 됐군.","JPN":"はは、やっとアクセスできたな。","ENG":"Haha! I finally managed to log in.","TWN":"哈哈，終於登入了。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CHEOLSU_LEGACY_NULL_NPC","text":{"KOREA":"마침 시설에 한 자리가 비어서 다행이야. 그럼 어디…….","JPN":"ちょうど施設に空きができてよかった。どれどれ……","ENG":"Thank goodness there was a vacant seat at the facility. Now then...","TWN":"正好店裡有一個空位，真是太好了。我來看看……"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CONSOLE_LEGACY_NULL_EXTRA","text":{"KOREA":"위험합니다! 지금 접속하시면 안 돼요!","JPN":"ダメです！　今ログインするのは危険です！","ENG":"NO! It's too dangerous to log in right now!","TWN":"危險！現在不能登入！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONSOLE_LEGACY_NULL_EXTRA","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHEOLSU_LEGACY_NULL_NPC","text":{"KOREA":"네, 네……?! 어째서죠?","JPN":"え、はい……！？　どうしてですか？","ENG":"W-what...? How so?","TWN":"好的，好的……？！為什麼？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONSOLE_LEGACY_NULL_EXTRA","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CONSOLE_LEGACY_NULL_EXTRA","text":{"KOREA":"뉴스 안 보십니까? 지금 접속하면 큰일 난다고요!","JPN":"ニュースを見なかったんですか？　今アクセスすると大変なことになりますよ！","ENG":"Don't you watch the news? You'll be in big trouble if you log in now!","TWN":"你沒看新聞嗎？現在登入會出大事的！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONSOLE_LEGACY_NULL_EXTRA","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CONSOLE_LEGACY_NULL_EXTRA","text":{"KOREA":"유저들이 원인 모를 이유로 폭주하고 난리도 아니에요! 아무튼 접속하시면 위험합니다!","JPN":"ユーザーたちが原因不明の暴走を起こして……とにかく今は危険です！","ENG":"The players are running wild and making a mess for unknown reasons! Anyway, you can't log in!","TWN":"玩家們因為不明原因暴走了，簡直一團糟！總之，登入的話很危險！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONSOLE_LEGACY_NULL_EXTRA","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHEOLSU_LEGACY_NULL_NPC","text":{"KOREA":"그, 그건 큰일이군요……!","JPN":"そ、それは大変ですね……！","ENG":"Th-that doesn't sound good...!","TWN":"那，那可糟了……！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONSOLE_LEGACY_NULL_EXTRA","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CONSOLE_LEGACY_NULL_EXTRA","text":{"KOREA":"당연하죠! 환불이라면 바로 해드릴 테니까……!","JPN":"そうなんです！　返金ならすぐにしますから……！","ENG":"No, it doesn't! I'll refund you right now, so–","TWN":"當然了！現在可以幫你進行退款……！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONSOLE_LEGACY_NULL_EXTRA","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CONSOLE_LEGACY_NULL_EXTRA","text":{"KOREA":"하, 하필 왜 이럴 때 손님들이 몰려오는 거야?","JPN":"よ、よりによってなんでこんな時に客が押し寄せてくるんだ！？","ENG":"Th-this is the worst time for customers to be flooding in...!","TWN":"為，為什麼偏偏在這個時候客人們都湧過來了？"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONSOLE_LEGACY_NULL_EXTRA","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CONSOLE_LEGACY_NULL_EXTRA","text":{"KOREA":"지금은 시설 이용 못 합니다! 모두 나가주세요!","JPN":"今は施設の利用はできません！　お帰りください！","ENG":"Everyone, please leave! The facility is currently unavailable!","TWN":"現在不能使用機台！請大家離開！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"비켜! 난 지금 당장 접속해야 해! ","JPN":"どけ！　今すぐ行かないといけないんだ！ ","ENG":"Outta my way! I need to log in right now! ","TWN":"讓開！我現在必須馬上登入！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_FIGHT"},{"id":"L14_1","type":"dialog","speaker":"CONSOLE_LEGACY_NULL_EXTRA","text":{"KOREA":"소, 손님! 이러시면 안 됩니다!","JPN":"お、お客様！　落ち着いてください！","ENG":"S-sir! What do you think you're doing?!","TWN":"客，客人！現在不能登入遊戲！"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CHEOLSU_LEGACY_NULL_NPC","text":{"KOREA":"아무래도…… 게임 속에 도움이 필요한 사람이 있는 것 같군.","JPN":"どうやら……ゲームの中に助けが必要な人がいるようだ。","ENG":"It seems... there's someone within the game that needs a helping hand.","TWN":"看來……遊戲裡有人需要幫助。"},"stage":{"bg":"TRAINING","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};